use crate::model::{Observation, State};

pub fn mote_e(a: &mut State, b: &str, c: bool) -> Observation {
    let query_epoch = a.epoch;

    // Pick the definition that would be visible in the currently active roots.
    // If multiple candidates exist (e.g. after slot retargeting), take the most
    // recently indexed one for determinism.
    let mut best = None;
    for entry in a.entries.iter().filter(|e| e.symbol == b) {
        let Some(root) = a.active.get(&entry.slot) else {
            continue;
        };
        if !entry.path.starts_with(root) {
            continue;
        }
        match best {
            None => best = Some(entry),
            Some(prev) if entry.epoch >= prev.epoch => best = Some(entry),
            Some(_) => {}
        }
    }

    if let Some(entry) = best {
        let reused = a
            .last_seen
            .get(b)
            .map(|old| *old == entry.handle)
            .unwrap_or(false);
        a.last_seen.insert(b.to_string(), entry.handle);

        Observation {
            label: String::new(),
            symbol: b.to_string(),
            found: true,
            path: entry.path.clone(),
            source: entry.source.clone(),
            line: entry.line,
            epoch: query_epoch,
            reused,
            fresh: true,
        }
    } else {
        // For misses, `fresh` means the miss is correct.
        Observation::missing(b, b, a.epoch, !c)
    }
}
EOF

